import { Type } from './Type.js';
/** Maps a database TEXT column (unbounded length) to a JS `string`. */
export class TextType extends Type {
    getColumnType(prop, platform) {
        return platform.getTextTypeDeclarationSQL(prop);
    }
    compareAsType() {
        return 'string';
    }
    ensureComparable() {
        return false;
    }
}
